package com.example.biometricauth

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.provider.Settings
import android.widget.Button
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import java.util.concurrent.Executor

class MainActivity : AppCompatActivity() {

    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo
    private lateinit var executor: Executor
    private lateinit var sharedPreferences: SharedPreferences

    private val AUTH_PREFS = "AuthPrefs"
    private val AUTH_SUCCESSFUL = "AuthSuccessful"

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        sharedPreferences = getSharedPreferences(AUTH_PREFS, Context.MODE_PRIVATE)

        if (sharedPreferences.getBoolean(AUTH_SUCCESSFUL, false)) {
            navigateToHomeScreen()
            return
        }

        val authenticateButton: Button = findViewById(R.id.authenticateButton)
        val statusTextView: TextView = findViewById(R.id.statusTextView)

        executor = ContextCompat.getMainExecutor(this)

        biometricPrompt = BiometricPrompt(this, executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    statusTextView.text = "Authentication error: $errString"
                    Toast.makeText(applicationContext, "Authentication error: $errString", Toast.LENGTH_SHORT).show()
                    // Fallback to password or PIN
                    showPasswordFallback()
                }

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    statusTextView.text = "Authentication Succeeded!"
                    Toast.makeText(applicationContext, "Authentication Succeeded!", Toast.LENGTH_SHORT).show()
                    sharedPreferences.edit().putBoolean(AUTH_SUCCESSFUL, true).apply()
                    navigateToHomeScreen()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    statusTextView.text = "Authentication Failed."
                    Toast.makeText(applicationContext, "Authentication Failed.", Toast.LENGTH_SHORT).show()
                }
            })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Biometric login for my app")
            .setSubtitle("Log in using your fingerprint or face")
            .setNegativeButtonText("Use account password") // This will trigger onAuthenticationError with errorCode=BiometricPrompt.ERROR_USER_CANCELED
            .setAllowedAuthenticators(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.DEVICE_CREDENTIAL)
            .build()

        authenticateButton.setOnClickListener {
            checkBiometricSupportAndAuthenticate()
        }
    }

    private fun checkBiometricSupportAndAuthenticate() {
        val biometricManager = BiometricManager.from(this)
        when (biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.DEVICE_CREDENTIAL)) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                findViewById<TextView>(R.id.statusTextView).text = "App can authenticate using biometrics."
                biometricPrompt.authenticate(promptInfo)
            }
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> {
                findViewById<TextView>(R.id.statusTextView).text = "No biometric features available on this device."
                Toast.makeText(this, "No biometric features available.", Toast.LENGTH_LONG).show()
                showPasswordFallback()
            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                findViewById<TextView>(R.id.statusTextView).text = "Biometric features are currently unavailable."
                Toast.makeText(this, "Biometric features unavailable.", Toast.LENGTH_LONG).show()
                showPasswordFallback()
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                findViewById<TextView>(R.id.statusTextView).text = "No biometrics enrolled. Please enroll biometrics in settings."
                Toast.makeText(this, "No biometrics enrolled. Please enroll in settings.", Toast.LENGTH_LONG).show()
                // Prompts the user to create credentials that your app accepts.
                val enrollIntent = Intent(Settings.ACTION_BIOMETRIC_ENROLL).apply {
                    putExtra(Settings.EXTRA_BIOMETRIC_AUTHENTICATORS_ALLOWED,
                        BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.DEVICE_CREDENTIAL)
                }
                startActivity(enrollIntent)
                showPasswordFallback()
            }
            else -> {
                findViewById<TextView>(R.id.statusTextView).text = "Unknown biometric error."
                Toast.makeText(this, "Unknown biometric error.", Toast.LENGTH_LONG).show()
                showPasswordFallback()
            }
        }
    }

    private fun showPasswordFallback() {
        // In a real app, this would navigate to a traditional login screen
        // or show a dialog for password/PIN entry.
        Toast.makeText(this, "Falling back to password/PIN login.", Toast.LENGTH_LONG).show()
        findViewById<TextView>(R.id.statusTextView).text = "Please enter your password/PIN."
        // For demonstration, we'll just simulate a successful password login after a delay
        // In a real app, you'd have a UI for this and actual password verification.
        findViewById<Button>(R.id.authenticateButton).text = "Login with Password"
        findViewById<Button>(R.id.authenticateButton).setOnClickListener {
            // Simulate password verification success
            Toast.makeText(this, "Password login successful!", Toast.LENGTH_SHORT).show()
            sharedPreferences.edit().putBoolean(AUTH_SUCCESSFUL, true).apply()
            navigateToHomeScreen()
        }
    }

    private fun navigateToHomeScreen() {
        val intent = Intent(this, HomeScreenActivity::class.java)
        startActivity(intent)
        finish() // Prevent going back to login screen with back button
    }
}

// HomeScreenActivity.kt
package com.example.biometricauth

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.widget.Button
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity

class HomeScreenActivity : AppCompatActivity() {

    private lateinit var sharedPreferences: SharedPreferences
    private val AUTH_PREFS = "AuthPrefs"
    private val AUTH_SUCCESSFUL = "AuthSuccessful"

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_home_screen)

        sharedPreferences = getSharedPreferences(AUTH_PREFS, Context.MODE_PRIVATE)

        val welcomeText: TextView = findViewById(R.id.welcomeText)
        welcomeText.text = "Welcome! You are authenticated."

        val logoutButton: Button = findViewById(R.id.logoutButton)
        logoutButton.setOnClickListener {
            sharedPreferences.edit().putBoolean(AUTH_SUCCESSFUL, false).apply()
            val intent = Intent(this, MainActivity::class.java)
            startActivity(intent)
            finish()
        }
    }
}

